  ('locality-d0d1b9a2-moex-00284', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司有A、B兩部門，A部門生產零件並以$20之價格對外銷售。A部門目前利用了60% 的產能，生產每單位零件的固定成本為$5，變動成本為$12。B部門想以$10向A部門購買這 個零件，A部門發現仍有足夠產能生產。若A、B兩部門的主管績效是以部門報導的利潤衡 量，下列何者為A、B兩部門主管議價能力相當下可能之轉撥價格？', '["$10", "$12", "$18", "$20"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
